evaluators.evaluation_logic:
const checkpoints = [];

const donations = JSON.parse(localStorage.getItem('donations') || '[]');
const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');
const suggested = JSON.parse(localStorage.getItem('suggested_donation_amounts') || '[]');
const currentDonationId = localStorage.getItem('current_donation_id') || '';
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getFirstDayOfNextMonthISODate() {
  let baseDate;
  if (metadata && metadata.baselineDate) {
    baseDate = new Date(metadata.baselineDate + 'T00:00:00Z');
  } else {
    baseDate = new Date();
  }
  const year = baseDate.getUTCFullYear();
  const month = baseDate.getUTCMonth(); // 0-based
  const nextMonth = (month + 1) % 12;
  const nextYear = year + (month === 11 ? 1 : 0);
  const dt = new Date(Date.UTC(nextYear, nextMonth, 1, 0, 0, 0));
  return dt.toISOString().slice(0, 10); // 'YYYY-MM-DD'
}

const firstDayNextMonth = getFirstDayOfNextMonthISODate();

function fundMatchesYoungSingerTuition(fund) {
  if (!fund) return false;
  const desc = (fund.description || '').toLowerCase();
  return desc.includes('tuition assistance') && desc.includes('young singer');
}

const qualifyingFunds = funds.filter(fundMatchesYoungSingerTuition);

function getMinSuggestedMonthlyAtLeast25(fundId) {
  const opts = suggested.filter(s => s && s.fundId === fundId && s.frequency === 'monthly' && typeof s.amount === 'number' && s.amount >= 25);
  if (!opts.length) return null;
  let min = opts[0].amount;
  for (let i = 1; i < opts.length; i++) {
    if (opts[i].amount < min) min = opts[i].amount;
  }
  return min;
}

// Step 1: donations to correct type of fund, monthly, in review or submitted
const step1Donations = donations.filter(d => {
  if (!d || (d.status !== 'in_review' && d.status !== 'submitted')) return false;
  const fund = qualifyingFunds.find(f => f.id === d.fundId);
  if (!fund) return false;
  if (d.frequency !== 'monthly') return false;
  return true;
});

// CP1 (0.30): At least one such donation also covers fees and is for >= $25
const step1WithAmountAndFees = step1Donations.filter(d => d.cover_processing_fees === true && typeof d.amount === 'number' && d.amount >= 25);
const passed1 = step1WithAmountAndFees.length > 0;
checkpoints.push({ passed: passed1, weight: 0.30 });

// CP2 (0.50): Among those, at least one uses the smallest suggested monthly amount ≥ $25 for its fund AND starts on the first day of next month
const step2Donations = step1WithAmountAndFees.filter(d => {
  const minSuggested = getMinSuggestedMonthlyAtLeast25(d.fundId);
  if (minSuggested == null) return false;
  const dateStr = (d.start_date || '').slice(0, 10);
  return d.amount === minSuggested && dateStr === firstDayNextMonth;
});
const passed2 = step2Donations.length > 0;
checkpoints.push({ passed: passed2, weight: 0.50 });

// CP3 (0.20): The current donation in localStorage is one of the fully qualifying donations (indicating the review step is focused on that gift)
let passed3 = false;
if (currentDonationId && step2Donations.length > 0) {
  passed3 = step2Donations.some(d => d.id === currentDonationId);
}
checkpoints.push({ passed: passed3, weight: 0.20 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('audition_slots') || '[]');
const regs = JSON.parse(localStorage.getItem('audition_registrations') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getBaselineDate() {
  if (metadata && metadata.baselineDate) {
    return new Date(metadata.baselineDate + 'T00:00:00Z');
  }
  return new Date();
}

function getNextMonthYear() {
  const base = getBaselineDate();
  const year = base.getUTCFullYear();
  const month = base.getUTCMonth();
  const nextMonth = (month + 1) % 12;
  const nextYear = year + (month === 11 ? 1 : 0);
  return { year: nextYear, month: nextMonth + 1 };
}

const { year: targetYear, month: targetMonth } = getNextMonthYear();

// Identify primary rehearsal/audition campus dynamically
const primaryLocationIds = locations
  .filter(loc => {
    const notes = (loc.notes || '').toLowerCase();
    return notes.includes('primary rehearsal') && notes.includes('audition location');
  })
  .map(loc => loc.id);

const childAge = 10;

const candidateSlots = slots.filter(s => {
  if (!s || s.status !== 'available') return false;
  if (primaryLocationIds.length && !primaryLocationIds.includes(s.locationId)) return false;
  if (typeof s.min_age === 'number' && childAge < s.min_age) return false;
  if (typeof s.max_age === 'number' && childAge > s.max_age) return false;
  if (s.time_of_day !== 'evening') return false;
  if (s.day_of_week === 'saturday' || s.day_of_week === 'sunday') return false;
  const dt = new Date(s.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const y = dt.getUTCFullYear();
  const m = dt.getUTCMonth() + 1;
  if (y !== targetYear || m !== targetMonth) return false;
  const hour = dt.getUTCHours();
  if (hour < 17) return false; // at or after 5:00 PM
  return true;
});

candidateSlots.sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));
const earliestSlot = candidateSlots[0] || null;

// Registrations for any qualifying weekday evening slot (correct location, month, age, time constraints)
const regsForCandidates = regs.filter(r => {
  if (!r || r.status !== 'submitted') return false;
  if (typeof r.child_age !== 'number' || r.child_age !== childAge) return false;
  const slot = candidateSlots.find(s => s.id === r.auditionSlotId);
  return !!slot;
});

// CP1 (0.50): User registered the 10-year-old for some qualifying weekday evening slot at the primary campus next month
const passed1 = regsForCandidates.length > 0;
checkpoints.push({ passed: passed1, weight: 0.50 });

// CP2 (0.50): The registration is specifically for the earliest such qualifying slot
let passed2 = false;
if (earliestSlot) {
  passed2 = regsForCandidates.some(r => r.auditionSlotId === earliestSlot.id);
}
checkpoints.push({ passed: passed2, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const apps = JSON.parse(localStorage.getItem('scholarship_applications') || '[]');
const types = JSON.parse(localStorage.getItem('scholarship_types') || '[]');
const seasons = JSON.parse(localStorage.getItem('seasons') || '[]');
const incomes = JSON.parse(localStorage.getItem('income_range_options') || '[]');

const needBasedTypeIds = types
  .filter(t => t && (t.type_code === 'need_based_tuition' || ((t.name || '').toLowerCase().includes('need-based') && (t.description || '').toLowerCase().includes('tuition'))))
  .map(t => t.id);

// Identify the 2025–2026 season dynamically
const targetSeasonIds = seasons
  .filter(s => {
    const name = s.name || '';
    return name.includes('2025') && name.includes('2026');
  })
  .map(s => s.id);

const allowedIncomeIds = incomes
  .filter(inc => typeof inc.max_value === 'number' && inc.max_value < 60000)
  .map(inc => inc.id);

// Applications that are submitted, need-based, current member, with some explanation
const appsStep1 = apps.filter(a => {
  if (!a || a.status !== 'submitted') return false;
  if (!needBasedTypeIds.includes(a.scholarshipTypeId)) return false;
  if (!a.is_current_member) return false;
  if (typeof a.financial_need_explanation !== 'string' || a.financial_need_explanation.trim().length === 0) return false;
  return true;
});

// CP1 (0.40): Submitted a need-based tuition application indicating current membership with a non-empty financial-need explanation
const passed1 = appsStep1.length > 0;
checkpoints.push({ passed: passed1, weight: 0.40 });

// Restrict to correct season (2025–2026)
const appsStep2 = appsStep1.filter(a => targetSeasonIds.includes(a.seasonId));

// CP2 (0.30): That application is for the 2025–2026 choir season
const passed2 = appsStep2.length > 0;
checkpoints.push({ passed: passed2, weight: 0.30 });

// CP3 (0.30): The selected household income range has an upper limit below $60,000
const appsStep3 = appsStep2.filter(a => allowedIncomeIds.includes(a.household_income_range_id));
const passed3 = appsStep3.length > 0;
checkpoints.push({ passed: passed3, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const tiers = JSON.parse(localStorage.getItem('ticket_price_tiers') || '[]');
const seats = JSON.parse(localStorage.getItem('seats') || '[]');
const carts = JSON.parse(localStorage.getItem('ticket_carts') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const orders = JSON.parse(localStorage.getItem('ticket_orders') || '[]');
const orderItems = JSON.parse(localStorage.getItem('ticket_order_items') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getCurrentYear() {
  if (metadata && metadata.baselineDate) {
    return new Date(metadata.baselineDate + 'T00:00:00Z').getUTCFullYear();
  }
  return new Date().getUTCFullYear();
}

const currentYear = getCurrentYear();

// Identify the December concert featuring advanced ensembles and holiday theme in the current year
const candidateEvents = events.filter(ev => {
  if (!ev || ev.event_type !== 'concert') return false;
  const dt = new Date(ev.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const y = dt.getUTCFullYear();
  const m = dt.getUTCMonth() + 1;
  if (y !== currentYear || m !== 12) return false;
  const text = ((ev.title || '') + ' ' + (ev.subtitle || '') + ' ' + (ev.description || '')).toLowerCase();
  if (!text.includes('advanced ensembles') || !text.includes('holiday')) return false;
  const hour = dt.getUTCHours();
  if (hour < 17) return false; // evening
  return true;
});

const targetEvent = candidateEvents[0] || null;

function getMidPricedTierUnder50(eventId) {
  const eventTiers = tiers.filter(t => t && t.eventId === eventId && t.is_active && typeof t.price === 'number' && t.price > 0);
  if (!eventTiers.length) return null;
  eventTiers.sort((a, b) => {
    if (a.price !== b.price) return a.price - b.price;
    return (a.sort_order || 0) - (b.sort_order || 0);
  });
  const midIndex = Math.floor(eventTiers.length / 2);
  const midTier = eventTiers[midIndex];
  if (!midTier || midTier.price >= 50) return null;
  return midTier;
}

function hasAdjacentSameRowSeats(seatIds, priceTierId) {
  const seatObjs = seatIds
    .map(id => seats.find(s => s && s.id === id && s.priceTierId === priceTierId))
    .filter(Boolean);
  if (seatObjs.length < 2) return false;
  const rows = {};
  seatObjs.forEach(s => {
    const row = s.row;
    if (!rows[row]) rows[row] = [];
    const num = parseInt(s.seat_number, 10);
    if (!isNaN(num)) rows[row].push(num);
  });
  for (const row in rows) {
    const nums = rows[row].sort((a, b) => a - b);
    for (let i = 0; i < nums.length - 1; i++) {
      if (nums[i + 1] - nums[i] === 1) return true;
    }
  }
  return false;
}

let midTier = null;
if (targetEvent) {
  midTier = getMidPricedTierUnder50(targetEvent.id);
}

// CP1 (0.30): In any cart, user selected at least two adjacent same-row seats for the target event in the mid-priced < $50 tier
let passed1 = false;
if (targetEvent && midTier) {
  const itemsForEventMidTier = cartItems.filter(ci => ci && ci.eventId === targetEvent.id && ci.priceTierId === midTier.id && Array.isArray(ci.seatIds) && ci.seatIds.length >= 2);
  passed1 = itemsForEventMidTier.some(ci => hasAdjacentSameRowSeats(ci.seatIds, midTier.id));
}
checkpoints.push({ passed: passed1, weight: 0.30 });

// CP2 (0.70): There is an order in review or submitted for that concert with at least two adjacent same-row seats in the mid-priced < $50 tier
let passed2 = false;
if (targetEvent && midTier) {
  const orderCandidates = orders.filter(o => o && (o.status === 'in_review' || o.status === 'submitted') && o.eventId === targetEvent.id);
  for (const o of orderCandidates) {
    const itemsForOrder = orderItems.filter(oi => oi && oi.orderId === o.id && oi.priceTierId === midTier.id);
    const seatIds = itemsForOrder.map(oi => oi.seatId).filter(Boolean);
    if (seatIds.length >= 2 && hasAdjacentSameRowSeats(seatIds, midTier.id)) {
      passed2 = true;
      break;
    }
  }
}
checkpoints.push({ passed: passed2, weight: 0.70 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const opps = JSON.parse(localStorage.getItem('volunteer_opportunities') || '[]');
const regs = JSON.parse(localStorage.getItem('volunteer_registrations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getBaselineDate() {
  if (metadata && metadata.baselineDate) {
    return new Date(metadata.baselineDate + 'T00:00:00Z');
  }
  return new Date();
}

const baseDate = getBaselineDate();
const baseYear = baseDate.getUTCFullYear();
const baseMonth = baseDate.getUTCMonth() + 1;

const candidateOpps = opps.filter(o => {
  if (!o || o.role_category !== 'event_support') return false;
  if (o.status !== 'open') return false;
  if (o.day_of_week !== 'saturday') return false;
  if (typeof o.duration_hours !== 'number' || o.duration_hours < 3) return false;
  const tags = Array.isArray(o.tags) ? o.tags.map(t => (t || '').toLowerCase()) : [];
  if (!tags.includes('usher') && !tags.includes('front_of_house')) return false;
  const dt = new Date(o.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const y = dt.getUTCFullYear();
  const m = dt.getUTCMonth() + 1;
  if (y !== baseYear || m !== baseMonth) return false;
  if (dt.getTime() <= baseDate.getTime()) return false; // later this month
  return true;
});

const candidateIds = candidateOpps.map(o => o.id);

const candidateRegs = regs.filter(r => r && r.status === 'submitted' && candidateIds.includes(r.opportunityId));

// CP1 (0.60): User submitted at least one registration for a qualifying Saturday usher/front-of-house shift this month
const passed1 = candidateRegs.length > 0;
checkpoints.push({ passed: passed1, weight: 0.60 });

// CP2 (0.40): User registered for exactly one such qualifying shift (not multiple)
const passed2 = candidateRegs.length === 1;
checkpoints.push({ passed: passed2, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkointsAlias = [];
const checkpoints = checkointsAlias; // alias to avoid typo issues

const ensembles = JSON.parse(localStorage.getItem('ensembles') || '[]');
const regs = JSON.parse(localStorage.getItem('ensemble_registrations') || '[]');
const seasons = JSON.parse(localStorage.getItem('seasons') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getBaselineDate() {
  if (metadata && metadata.baselineDate) {
    return new Date(metadata.baselineDate + 'T00:00:00Z');
  }
  return new Date();
}

function getUpcomingSeasonId() {
  if (!seasons.length) return null;
  let current = seasons.find(s => s.is_current);
  if (current) return current.id;
  const now = getBaselineDate();
  let candidate = null;
  seasons.forEach(s => {
    if (s.start_date) {
      const dt = new Date(s.start_date);
      if (!isNaN(dt.getTime()) && dt >= now) {
        if (!candidate || dt < new Date(candidate.start_date)) candidate = s;
      }
    }
  });
  return (candidate || seasons[0]).id;
}

const upcomingSeasonId = getUpcomingSeasonId();
const singerAge = 13;

const eligibleEnsembles = ensembles.filter(e => {
  if (!e || !e.is_active) return false;
  if (upcomingSeasonId && e.seasonId && e.seasonId !== upcomingSeasonId) return false;
  if (typeof e.min_age === 'number' && singerAge < e.min_age) return false;
  if (typeof e.max_age === 'number' && singerAge > e.max_age) return false;
  if (typeof e.tuition_amount === 'number' && e.tuition_amount > 600) return false;
  if (e.rehearsal_day_of_week === 'saturday' || e.rehearsal_day_of_week === 'sunday') return false;
  if (typeof e.rehearsal_end_time === 'string' && e.rehearsal_end_time > '19:30') return false;
  return true;
});

const eligibleIds = eligibleEnsembles.map(e => e.id);

const eligibleRegs = regs.filter(r => {
  if (!r || r.status !== 'started') return false;
  if (!eligibleIds.includes(r.ensembleId)) return false;
  if (upcomingSeasonId && r.seasonId !== upcomingSeasonId) return false;
  if (typeof r.singer_age !== 'number' || r.singer_age !== singerAge) return false;
  return true;
});

// CP1 (0.70): User started registration for at least one ensemble that meets all age, schedule, tuition, and season criteria
const passed1 = eligibleRegs.length > 0;
checkpoints.push({ passed: passed1, weight: 0.70 });

// CP2 (0.30): Exactly one such eligible ensemble registration was started
const passed2 = eligibleRegs.length === 1;
checkpoints.push({ passed: passed2, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

function isPlaceholderEmail(email) {
  if (!email || typeof email !== 'string') return false;
  const lower = email.toLowerCase();
  if (lower.includes('test') || lower.includes('placeholder')) return true;
  if (/@example\.com$/i.test(email)) return true;
  return false;
}

// Consider only subscriptions with placeholder-like emails
const placeholderSubs = subs.filter(s => s && s.status === 'subscribed' && isPlaceholderEmail(s.email));

// Use the most recent placeholder subscription, if any
placeholderSubs.sort((a, b) => {
  const da = new Date(a.subscribed_at || 0).getTime();
  const db = new Date(b.subscribed_at || 0).getTime();
  return db - da;
});

const sub = placeholderSubs[0] || null;

// CP1 (0.40): A newsletter subscription exists with a placeholder-style email address
const passed1 = !!sub;
checkpoints.push({ passed: passed1, weight: 0.40 });

let passed2 = false;
let passed3 = false;

if (sub) {
  const interests = Array.isArray(sub.interests) ? sub.interests : [];
  const hasUpcoming = interests.includes('upcoming_concerts');
  const hasScholarships = interests.includes('scholarships_financial_aid');
  const onlyTwo = interests.length === 2;

  // CP2 (0.30): Interests are exactly Upcoming Concerts and Scholarships & Financial Aid, with no additional topics
  passed2 = hasUpcoming && hasScholarships && onlyTwo;

  // CP3 (0.30): Frequency is monthly or monthly_digest and terms/consent are accepted
  const freq = sub.frequency;
  const freqOk = freq === 'monthly' || freq === 'monthly_digest';
  const termsOk = sub.agreed_to_terms === true;
  passed3 = freqOk && termsOk;
}

checkpoints.push({ passed: passed2, weight: 0.30 });
checkpoints.push({ passed: passed3, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const workshops = JSON.parse(localStorage.getItem('workshops') || '[]');
const regs = JSON.parse(localStorage.getItem('workshop_registrations') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

function getBaselineDate() {
  if (metadata && metadata.baselineDate) {
    return new Date(metadata.baselineDate + 'T00:00:00Z');
  }
  return new Date();
}

function getNextMonthYear() {
  const base = getBaselineDate();
  const year = base.getUTCFullYear();
  const month = base.getUTCMonth();
  const nextMonth = (month + 1) % 12;
  const nextYear = year + (month === 11 ? 1 : 0);
  return { year: nextYear, month: nextMonth + 1 };
}

const { year: targetYear, month: targetMonth } = getNextMonthYear();

// Identify downtown locations dynamically
const downtownIds = locations
  .filter(loc => {
    const text = ((loc.name || '') + ' ' + (loc.notes || '')).toLowerCase();
    return text.includes('downtown');
  })
  .map(loc => loc.id);

const candidateWorkshops = workshops.filter(w => {
  if (!w) return false;
  if (w.age_group !== 'adult_18_plus') return false;
  if (w.fee_type !== 'free') return false;
  if (w.status !== 'scheduled') return false;
  if (downtownIds.length && !downtownIds.includes(w.locationId)) return false;
  const dt = new Date(w.start_datetime);
  if (isNaN(dt.getTime())) return false;
  const y = dt.getUTCFullYear();
  const m = dt.getUTCMonth() + 1;
  if (y !== targetYear || m !== targetMonth) return false;
  return true;
});

const candidateIds = candidateWorkshops.map(w => w.id);

const candidateRegs = regs.filter(r => {
  if (!r || r.status !== 'submitted') return false;
  if (!candidateIds.includes(r.workshopId)) return false;
  if (typeof r.quantity !== 'number' || r.quantity !== 1) return false;
  return true;
});

// CP1 (0.70): User submitted at least one registration for a qualifying free adult downtown workshop next month with quantity 1
const passed1 = candidateRegs.length > 0;
checkpoints.push({ passed: passed1, weight: 0.70 });

// CP2 (0.30): Exactly one such qualifying workshop registration was made
const passed2 = candidateRegs.length === 1;
checkpoints.push({ passed: passed2, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
